import { Container, Row, Col } from 'react-bootstrap';
import "../styles/CustomParallax.css";

function CustomParallax({ scrollPercentage, layers }) {
  return (
    <div className="CustomParallax">
      <Container>
        <Row className="justify-content-center align-items-center">
          {layers.map((layer, index) => (
            <Col key={index} xs={12} className={`Layer${index + 1}`}>
              <div
                className="parallax-layer"
                style={{
                  backgroundImage: `url(${layer.imgSrc})`,
                  backgroundPositionX: `calc(${scrollPercentage * layer.imgSpeed}% + ${layer.imgOffset})`,
                }}
              ></div>
            </Col>
          ))}
        </Row>
      </Container>
    </div>
  );
}

export default CustomParallax;
